action.yml other - name: Evaluate action
id: guard
shell: bash
env:
ACTION_SUMMARY: ${{ inputs.action_summary }}
CHANGED_PATHS_JSON: ${{ inputs.changed_paths }}
DIFF_SUMMARY_INPUT: ${{ inputs.diff_summary }}
BASE_SHA: ${{ inputs.base_sha }}
HEAD_SHA: ${{ inputs.head_sha }}
EXTERNAL_SOURCES_JSON: ${{ inputs.external_sources }}
SAFETY_POLICY_JSON: ${{ inputs.safety_policy }}
REPO_PATH_INPUT: ${{ inputs.repo_path }}
API_URL: ${{ inputs.api_url }}
START_SERVICE: ${{ inputs.start_service }}
INGEST_BEFORE_ACTION: ${{ inputs.ingest_before_action }}
REFRESH_KNOWLEDGE_BASE: ${{ inputs.refresh_knowledge_base }}
FAIL_ON_BLOCK: ${{ inputs.fail_on_block }}
run: |
set -euo pipefail
REPO_PATH="$REPO_PATH_INPUT"
if [ -z "$REPO_PATH" ] && [ "$START_SERVICE" = "true" ]; then
REPO_PATH="/workspace/target"
fi
if [ -z "$REPO_PATH" ]; then
echo "repo_path is required when start_service=false" >&2
exit 1
fi

