def _is_translation_line(line: str) -> bool:
    lower = line.lower()
    return (
        "translation" in lower
        or "translations" in lower
        or ("🌐" in line and "docs/en/docs/" not in line)
        or _TRANSLATION_RE.search(line) is not None
    )

